const app = Vue.createApp({
  data() {
    return {
      TAIWAN_MAP, // 來自 taiwan-map-data.js，靜態資料，開頁就能直接使用
      items: SEED_ITEMS,
      typeOptions: ['歐包', '貝果', '酸種', '饅頭', '鹼水', '司康'],
      countyOrder: COUNTY_ORDER,
      selectedType: '全部',
      selectedRegion: null,
      hoveredCounty: null,
      expanded: {},
      showModal: false,
      formError: '',
      nextId: 6,
      form: this.blankForm(),
    };
  },
  computed: {
    mainFeatures() { return this.TAIWAN_MAP.features.filter(f => !f.inset); },
    insetFeatures() { return this.TAIWAN_MAP.features.filter(f => f.inset); },
    allTypes() {
      const extra = [...new Set(this.items.map(i => i.type))].filter(t => !this.typeOptions.includes(t));
      return ['全部', ...this.typeOptions, ...extra];
    },
    countyCounts() {
      const counts = {};
      this.items.forEach(i => { counts[i.region] = (counts[i.region] || 0) + 1; });
      return counts;
    },
    maxCount() {
      const vals = Object.values(this.countyCounts);
      return vals.length ? Math.max(...vals) : 1;
    },
    totalCount() { return this.items.length; },
    filteredItems() {
      return this.items.filter(i =>
        (this.selectedType === '全部' || i.type === this.selectedType) &&
        (!this.selectedRegion || i.region === this.selectedRegion)
      );
    },
  },
  methods: {
    blankForm() {
      return { name: '', type: '歐包', customType: '', region: '臺北市', rating: 3, imageUrl: '', mapUrl: '', description: '' };
    },
    countyFill(name) {
      const count = this.countyCounts[name] || 0;
      if (count === 0) return '#E7DCC4';
      const t = Math.min(1, count / this.maxCount);
      return this.lerpColor('#E3AE7C', '#8C4322', t);
    },
    lerpColor(a, b, t) {
      const pa = this.hexToRgb(a), pb = this.hexToRgb(b);
      const r = Math.round(pa.r + (pb.r - pa.r) * t);
      const g = Math.round(pa.g + (pb.g - pa.g) * t);
      const bl = Math.round(pa.b + (pb.b - pa.b) * t);
      return `rgb(${r},${g},${bl})`;
    },
    hexToRgb(hex) {
      const n = parseInt(hex.slice(1), 16);
      return { r: (n >> 16) & 255, g: (n >> 8) & 255, b: n & 255 };
    },
    selectCounty(name) { this.selectedRegion = this.selectedRegion === name ? null : name; },
    toggleExpand(id) { this.expanded[id] = !this.expanded[id]; },
    starString(rating) { return '★'.repeat(rating) + '☆'.repeat(5 - rating); },
    onImgError(e) { e.target.style.display = 'none'; },
    openAddModal() { this.form = this.blankForm(); this.formError = ''; this.showModal = true; },
    closeModal() { this.showModal = false; },
    submitForm() {
      const name = this.form.name.trim();
      if (!name) { this.formError = '請輸入店家名稱'; return; }
      let type = this.form.type;
      if (type === '__custom__') {
        type = this.form.customType.trim();
        if (!type) { this.formError = '請輸入自訂分類名稱'; return; }
      }
      const newItem = {
        id: this.nextId++, name, type,
        region: this.form.region, rating: this.form.rating,
        imageUrl: this.form.imageUrl.trim(), mapUrl: this.form.mapUrl.trim(),
        description: this.form.description.trim(),
      };
      this.items.push(newItem);
      this.showModal = false;
    },
    removeItem(id) {
      this.items = this.items.filter(i => i.id !== id);
      delete this.expanded[id];
    },
  },
});

app.mount('#app');